// HasMatchRound applies the HasEdge predicate on the "match_round" edge.
func HasMatchRound() predicate.RecordTask {
	return predicate.RecordTask(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, MatchRoundTable, MatchRoundColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasMatchRoundWith applies the HasEdge predicate on the "match_round" edge with a given conditions (other predicates).
func HasMatchRoundWith(preds ...predicate.MatchRound) predicate.RecordTask {
	return predicate.RecordTask(func(s *sql.Selector) {
		step := newMatchRoundStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

