// And groups predicates with the AND operator between them.
func And(predicates ...predicate.RecordTask) predicate.RecordTask {
	return predicate.RecordTask(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.RecordTask) predicate.RecordTask {
	return predicate.RecordTask(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.RecordTask) predicate.RecordTask {
	return predicate.RecordTask(sql.NotPredicates(p))
}
